if (File.Exists(releaseBinary))
        {
            context.Logger.LogDebug("Discovery: release prefix walk yielded '{Binary}'.", releaseBinary);
            yield return new InstallationDiscoveryCandidate(releaseBinary, "well-known release prefix");
        }
        else if (Directory.Exists(releaseDir))
        {
            // Bin dir exists but no `aspire` inside it: likely a partially removed install
            // or a third-party `~/.aspire/bin` use. Log so users can correlate with expectations.
            context.Logger.LogDebug(
                "Discovery: release prefix directory '{ReleaseDir}' exists but does not contain an 'aspire' binary — not classifying as a real install.",
                releaseDir);
        }
        else
        {
            context.Logger.LogDebug("Discovery: release prefix '{ReleaseDir}' does not exist; skipping.", releaseDir);
        }

if (remoteFetchEnabled)
        {
            githubResult = await InstallFromGitHubAsync(cacheRoot, effectiveVersion, validationDisabled, activity, cancellationToken).ConfigureAwait(false);
            if (githubResult.Status == AcquisitionStatus.Installed)
            {
                CleanupStaleCacheEntries(cacheRoot, effectiveVersion);
                return AspireSkillsInstallResult.Installed(githubResult.Bundle!);
            }

            if (githubResult.Status == AcquisitionStatus.Failed)
            {
                logger.LogDebug("Aspire skills GitHub acquisition failed for version {Version}; falling back to embedded snapshot. Failure: {Failure}", effectiveVersion, githubResult.Message);
            }
        }
        else
        {
            logger.LogDebug("Aspire skills remote fetch feature '{Feature}' is disabled; using the embedded snapshot.", KnownFeatures.AspireSkillsRemoteFetchEnabled);
        }

try
        {
            // Cached bundles are written by this installer (from GitHub or embedded sources).
            // The cache directory is keyed by bundle version, which is the right invalidation
            // signal, so skip the `supports` range check here — a previously-embedded snapshot
            // whose range no longer covers the current CLI is still the local artifact we
            // chose to use and should not be re-evicted on every invocation.
            var bundle = await LoadCachedBundleAsync(cacheDirectory, cancellationToken).ConfigureAwait(false);
            ValidateBundleVersion(bundle, version);
            TouchLastUsed(cacheDirectory);
            activity?.SetTag("aspire.skills.cache_hit", true);
            logger.LogDebug("Using cached Aspire skills bundle from {CacheDirectory}.", cacheDirectory);
            return bundle;
        }
        catch (InvalidOperationException ex)
        {
            logger.LogDebug(ex, "Ignoring invalid cached Aspire skills bundle at {CacheDirectory}.", cacheDirectory);
            return null;
        }

try
        {
            using var request = CreateGitHubRequest(attestationUrl);
            using var response = await httpClient.SendAsync(request, cancellationToken).ConfigureAwait(false);
            if (!response.IsSuccessStatusCode)
            {
                logger.LogDebug("Failed to fetch GitHub artifact attestations for {Repository} digest {Digest}: HTTP {StatusCode}", repository, digestHex, response.StatusCode);
                return new ProvenanceVerificationResult { Outcome = ProvenanceVerificationOutcome.AttestationFetchFailed };
            }

            attestationJson = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
        }
        catch (HttpRequestException ex)
        {
            logger.LogDebug(ex, "Failed to fetch GitHub artifact attestations for {Repository} digest {Digest}.", repository, digestHex);
            return new ProvenanceVerificationResult { Outcome = ProvenanceVerificationOutcome.AttestationFetchFailed };
        }

try
        {
            var dashboardUrls = await rpc.InvokeWithProfilingAsync<DashboardUrlsState?>(
                _profilingTelemetry,
                "auxiliary",
                "GetDashboardUrlsAsync",
                [],
                cancellationToken).ConfigureAwait(false);

            activity.SetAppHostDashboardUrls(dashboardUrls);
            activity.AddAuxBackchannelGetDashboardUrlsResponseEvent();

            return dashboardUrls;
        }
        catch (RemoteMethodNotFoundException ex)
        {
            // The RPC method may not be available on older AppHost versions.
            _logger.LogDebug(ex, "GetDashboardUrlsAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
            activity.AddAuxBackchannelGetDashboardUrlsNotFoundEvent();
            return null;
        }

try
        {
            logLines = await rpc.InvokeStreamingWithProfilingAsync<ResourceLogLine>(
                _profilingTelemetry,
                "auxiliary",
                "GetResourceLogsAsync",
                [resourceName, follow],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "GetResourceLogsAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
            yield break;
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            _logger.LogDebug(ex, "Error calling GetResourceLogsAsync RPC method. The AppHost may be running an incompatible version.");
            yield break;
        }

try
        {
            logBatches = await rpc.InvokeStreamingWithProfilingAsync<ResourceLogBatch>(
                _profilingTelemetry,
                "auxiliary",
                "GetConsoleLogBatchesAsync",
                [request],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "GetConsoleLogBatchesAsync RPC method not available on the remote AppHost. Falling back to log-line streaming.");
            var logLines = request.ResourceName is null
                ? GetResourceLogsAsync(resourceName: null, follow: request.Follow, cancellationToken: cancellationToken)
                : GetConsoleLogsAsync(request, cancellationToken);
            logBatches = BatchLogLinesAsync(logLines, request.Follow, cancellationToken);
        }

try
        {
            logLines = await rpc.InvokeStreamingWithProfilingAsync<ResourceLogLine>(
                _profilingTelemetry,
                "auxiliary",
                "GetConsoleLogsAsync",
                [request],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "GetConsoleLogsAsync RPC method not available on the remote AppHost. Falling back to GetResourceLogsAsync.");
            // Older AppHosts only expose the legacy stream and cannot apply server-side
            // search/tail. The LogsCommand keeps its client-side filters so output stays
            // correct even though this fallback has to transfer the full log stream.
            logLines = GetResourceLogsAsync(request.ResourceName, request.Follow, cancellationToken);
        }

foreach (var entry in Directory.EnumerateDirectories(versionsRoot))
        {
            var name = Path.GetFileName(entry);

            // Keep the active version.
            if (string.Equals(name, activeVersionId, StringComparison.Ordinal))
            {
                continue;
            }

            if (BundleVersionLease.HasActiveLease(entry))
            {
                continue;
            }

            try
            {
                Directory.Delete(entry, recursive: true);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                // If deletion fails after lease probing, leave the directory untouched.
                // A later setup/update can retry without invalidating a potential reader.
            }
        }

try
        {
            // We can't guarantee that the temp file is in a directory with sensible permissions, but we're not exporting the private key
            ExportCertificate(certificate, tmpFile, includePrivateKey: false, password: null, CertificateKeyExportFormat.Pem);

            using var checkTrustProcess = Process.Start(new ProcessStartInfo(
                MacOSVerifyCertificateCommandLine,
                string.Format(CultureInfo.InvariantCulture, MacOSVerifyCertificateCommandLineArgumentsFormat, tmpFile))
            {
                RedirectStandardOutput = true,
                // Do this to avoid showing output to the console when the cert is not trusted. It is trivial to export
                // the cert and replicate the command to see details.
                RedirectStandardError = true,
            });
            checkTrustProcess!.WaitForExit();
            return checkTrustProcess.ExitCode == 0 ? TrustLevel.Full : TrustLevel.None;
        }
        finally
        {
            File.Delete(tmpFile);
        }

if (combinedMcpApplicator is not null)
        {
            try
            {
                await combinedMcpApplicator.ApplyAsync(cancellationToken);
            }
            // InvalidOperationException is thrown by scanner-generated applicators
            // (e.g., MCP config writers) when the underlying operation fails.
            // JsonException as InnerException indicates a malformed config file
            // (e.g., invalid JSON in .copilot/mcp-config.json or .vscode/mcp.json).
            catch (InvalidOperationException ex)
            {
                InteractionService.DisplayError(ex.Message);
                if (ex.InnerException is JsonException)
                {
                    InteractionService.DisplaySubtleMessage(
                        string.Format(CultureInfo.CurrentCulture, AgentCommandStrings.SkippedMalformedConfigFile, combinedMcpApplicator.Description));
                }
                hasErrors = true;
            }
        }

if (result.ChildProcess is { HasExited: false } childProcess)
        {
            // Safety net for the hidden capture path: if the RPC stop did not bring the spawned
            // child CLI down within the grace period, terminate the process tree so we never
            // leave an orphaned AppHost behind.
            try
            {
                await childProcess.WaitForExitAsync(cancellationToken).WaitAsync(TimeSpan.FromSeconds(10), cancellationToken).ConfigureAwait(false);
            }
            catch (TimeoutException)
            {
                childProcess.Kill(entireProcessTree: true);
            }
            catch (OperationCanceledException) when (!childProcess.HasExited)
            {
                childProcess.Kill(entireProcessTree: true);
                throw;
            }
        }

using (var spawnActivity = profilingTelemetry.StartDetachedSpawnChild(executablePath, childArgs, "run"))
        {
            try
            {
                childProcess = detachedProcessLauncher.Start(
                    executablePath,
                    childArgs,
                    executionContext.WorkingDirectory.FullName,
                    IsExtensionEnvironmentVariable,
                    CreateDetachedChildEnvironment(Activity.Current));
                spawnActivity.SetProcessId(childProcess.Id);
            }
            catch (Exception ex)
            {
                spawnActivity.SetError(ex.Message);
                logger.LogError(ex, "Failed to start child CLI process");
                return new LaunchResult(null, null, null, false, 0);
            }
        }

try
        {
            return CommandResult.FromExitCode(await ExportDataAsync(resourceName, includeHidden, dashboardApi.Connection, dashboardApi.BaseUrl, dashboardApi.ApiToken, outputPath, cancellationToken));
        }
        catch (HttpRequestException ex) when (dashboardUrl is not null)
        {
            _logger.LogError(ex, "Failed to export telemetry data from dashboard");
            var errorInfo = await TelemetryCommandHelpers.FormatTelemetryErrorAsync(ex, dashboardApi.BaseUrl!, true, _httpClientFactory, _logger, cancellationToken);
            TelemetryCommandHelpers.DisplayTelemetryError(InteractionService, errorInfo);
            return CommandResult.Failure(CliExitCodes.DashboardFailure);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to export telemetry data");
            return CommandResult.Failure(CliExitCodes.DashboardFailure, string.Format(CultureInfo.CurrentCulture, ExportCommandStrings.FailedToExport, ex.Message));
        }

await foreach (var logLine in GetConsoleLogLinesAsync(connection, followRequest, cancellationToken).ConfigureAwait(false))
        {
            // When streaming all resources, skip logs from hidden resources.
            // We filter by exclusion so that new resources appearing after the
            // initial snapshot are included by default.
            if (resourceName is null && !resourceWatcher.IncludeHidden)
            {
                var resource = resourceWatcher.GetResource(logLine.ResourceName);
                if (resource is not null && ResourceSnapshotMapper.IsHiddenResource(resource))
                {
                    continue;
                }
            }

            var entry = ParseLogLine(logLine, logParser, resourceWatcher.GetAllResources());

            // Apply full-text search filter on streamed log content
            if (!string.IsNullOrEmpty(search) && !MatchesSearch(entry, search))
            {
                continue;
            }

            OutputLogLine(entry, format, timestamps);
        }

try
            {
                await foreach (var connections in _backchannelMonitor.WatchConnectionsAsync(followCancellationToken).WithCancellation(followCancellationToken).ConfigureAwait(false))
                {
                    await updates.Writer.WriteAsync(new ConnectionsUpdate(connections), followCancellationToken).ConfigureAwait(false);
                }
            }
            catch (OperationCanceledException) when (followCancellationToken.IsCancellationRequested)
            {
                // Expected when the caller stops following.
            }
            catch (Exception ex)
            {
                _logger.LogDebug(ex, "Failed while watching AppHost connections for ps --follow.");
            }
            finally
            {
                updates.Writer.TryComplete();
            }

if (request is null)
            {
                var exitCode = _defaultHelpAction.Invoke(parseResult);
                if (TryGetResourceOnlyHelp(parseResult, out var resourceName))
                {
                    try
                    {
                        await WriteAvailableCommandsAsync(parseResult, resourceName, cancellationToken).ConfigureAwait(false);
                    }
                    catch (Exception ex) when (ex is not OperationCanceledException)
                    {
                        command._logger.LogDebug(ex, "Failed to augment resource help with available resource commands.");
                    }
                }

                return exitCode;
            }

try
        {
            // The timeout is a safety net for the startup-timeout path (no Ctrl+C). When the user
            // presses Ctrl+C, cancellationToken fires and WaitAsync exits immediately via the token
            // rather than waiting for the full timeout duration.
            await pendingRun.WaitAsync(s_appHostStartupCancellationTimeout, _timeProvider, cancellationToken).ConfigureAwait(false);
        }
        catch (OperationCanceledException) when (runCancellationTokenSource.IsCancellationRequested || cancellationToken.IsCancellationRequested)
        {
        }
        catch (TimeoutException ex)
        {
            _logger.LogDebug(ex, "Timed out waiting for AppHost startup cancellation to complete.");
            _ = ObserveAppHostRunFailureAsync(pendingRun);
        }
        catch (Exception ex)
        {
            _logger.LogDebug(ex, "AppHost run failed after startup cancellation.");
        }

switch (result)
        {
            case BundleExtractResult.NoPayload:
                InteractionService.DisplayMessage(KnownEmojis.Information, "This CLI binary does not contain an embedded bundle. No extraction needed.");
                break;

            case BundleExtractResult.AlreadyUpToDate:
                InteractionService.DisplayMessage(KnownEmojis.CheckMarkButton, "Bundle is already extracted and up to date. Use --force to re-extract.");
                break;

            case BundleExtractResult.Extracted:
                InteractionService.DisplayMessage(KnownEmojis.CheckMarkButton, $"Bundle extracted to {installPath}");
                break;

            case BundleExtractResult.ExtractionFailed:
                return CommandResult.Failure(CliExitCodes.FailedToBuildArtifacts, $"Bundle was extracted to {installPath} but layout validation failed.");
        }

while (searchDirectory is not null)
        {
            // Prefer aspire.config.json (new format)
            var newSettingsPath = Path.Combine(searchDirectory.FullName, AspireConfigFile.FileName);
            if (File.Exists(newSettingsPath))
            {
                logger.LogInformation("Found settings file at {Path}", newSettingsPath);
                return newSettingsPath;
            }

            // TODO: Remove legacy .aspire/settings.json fallback once confident most users have migrated.
            // Tracked by https://github.com/microsoft/aspire/issues/15239
            // Fall back to .aspire/settings.json (legacy)
            var legacySettingsPath = ConfigurationHelper.BuildPathToSettingsJsonFile(searchDirectory.FullName);
            if (File.Exists(legacySettingsPath))
            {
                logger.LogInformation("Found legacy settings file at {Path}", legacySettingsPath);
                return legacySettingsPath;
            }

            searchDirectory = searchDirectory.Parent;
        }

if (ShouldExpandSearchWithMemberIndex(results, normalizedQuery, normalizedLanguage))
        {
            await EnsureCachedMemberItemsLoadedAsync(cancellationToken).ConfigureAwait(false);
            results = SearchIndexedItems(queryTokens, normalizedQuery, normalizedLanguage, topK);

            if (ShouldExpandSearchWithMemberIndex(results, normalizedQuery, normalizedLanguage))
            {
                foreach (var candidateContainerIds in GetCandidateMemberContainerIds(routeResults, queryTokens, normalizedLanguage).Chunk(MemberSearchBatchSize))
                {
                    await EnsureMemberContainersIndexedAsync(candidateContainerIds, cancellationToken).ConfigureAwait(false);
                    results = SearchIndexedItems(queryTokens, normalizedQuery, normalizedLanguage, topK);
                    if (results.Count >= topK)
                    {
                        break;
                    }
                }
            }
        }

foreach (var sourceGroup in patternsBySource)
        {
            var sourceUrl = sourceGroup.Key;
            // Use existing key if available, otherwise use the source URL as key
            var keyToUse = context.UrlToExistingKey.TryGetValue(sourceUrl, out var existingKey) ? existingKey : sourceUrl;

            var packageSource = new XElement("packageSource");
            packageSource.SetAttributeValue("key", keyToUse);

            foreach (var mapping in sourceGroup)
            {
                var packageElement = new XElement("package");
                packageElement.SetAttributeValue("pattern", mapping.PackageFilter);
                packageSource.Add(packageElement);
            }

            packageSourceMapping.Add(packageSource);
        }

try
        {
            var tempFilePath = Path.Combine(tempDirectory, "nuget.config");
            var configFile = new FileInfo(tempFilePath);
            await GenerateNuGetConfigAsync(mappings, configFile);
            if (configureGlobalPackagesFolder)
            {
                await AddGlobalPackagesFolderToConfigAsync(configFile, globalPackagesFolderValue);
            }
            return new TemporaryNuGetConfig(configFile);
        }
        catch
        {
            try
            {
                Directory.Delete(tempDirectory, recursive: true);
            }
            catch
            {
                // Ignore cleanup failures; surface the original exception instead.
            }
            throw;
        }

if (string.IsNullOrWhiteSpace(outputPath))
        {
            outputPath = Path.Combine(workingDirectory.FullName, CreateDefaultOutputFileName(timeProvider, sessionId));
        }
        else
        {
            if (!Path.IsPathRooted(outputPath))
            {
                outputPath = Path.Combine(workingDirectory.FullName, outputPath);
            }

            // Treat an existing directory, or a path with a trailing directory separator, as an
            // output directory and generate the same default archive name inside it. A non-existent
            // path without a trailing separator is preserved as the requested archive file path.
            if (Directory.Exists(outputPath) || Path.EndsInDirectorySeparator(outputPath))
            {
                outputPath = Path.Combine(outputPath, CreateDefaultOutputFileName(timeProvider, sessionId));
            }
        }

try
            {
                // Bound the wait so a Kill that fails or a process that refuses to terminate cannot
                // hang CLI shutdown. _dashboardExitTask was created with CancellationToken.None so
                // it survives the capture flow; apply the timeout here via WaitAsync instead of
                // tearing the underlying wait down.
                await _dashboardExitTask.WaitAsync(s_dashboardDisposeTimeout, _timeProvider).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
            }
            catch (TimeoutException ex)
            {
                _logger.LogDebug(ex, "Profile dashboard process did not exit within the disposal timeout.");
            }
            finally
            {
                _dashboardProcess.Dispose();
                _layoutLease?.Dispose();
            }

if (consoleLogLevel is not null)
            {
                builder.AddFilter("Aspire.Cli", consoleLogLevel.Value);
                builder.AddFilter("Microsoft.Hosting.Lifetime", LogLevel.Warning);
            }
            else
            {
                // Default writing debug level logs to file.
                builder.AddFilter<FileLoggerProvider>(null, LogLevel.Debug);

                // These categories are very verbose at Debug; suppress their Debug output by
                // raising the minimum to Information unless an explicit log level is requested.
                builder.AddFilter<FileLoggerProvider>("Microsoft.Extensions.Http.DefaultHttpClientFactory", LogLevel.Information);
                builder.AddFilter<FileLoggerProvider>("Aspire.Cli.Certificates.NativeCertificateToolRunner", LogLevel.Information);
            }

if (localeOverride is not null)
        {
            var result = LocaleHelpers.TrySetLocaleOverride(localeOverride);

            string errorMessage;
            switch (result)
            {
                case SetLocaleResult.Success:
                    return;
                case SetLocaleResult.InvalidLocale:
                    errorMessage = string.Format(CultureInfo.CurrentCulture, ErrorStrings.UnsupportedLocaleProvided, localeOverride, string.Join(", ", LocaleHelpers.SupportedLocales));
                    break;
                case SetLocaleResult.UnsupportedLocale:
                    errorMessage = string.Format(CultureInfo.CurrentCulture, ErrorStrings.InvalidLocaleProvided, localeOverride);
                    break;
                default:
                    throw new InvalidOperationException($"Unexpected result: {result}");
            }

            logger.LogError("Locale override failed: {ErrorMessage}", errorMessage);
            errorWriter.WriteLine(errorMessage);
        }

if (!string.IsNullOrWhiteSpace(restoreConfigFile))
        {
            // RestoreAdditionalProjectSources can add feeds, but it cannot carry package source
            // mappings. Use the temp NuGet.config so Aspire* packages stay pinned to the
            // explicit source while non-Aspire dependencies can use fallback sources.
            propertyGroup.Add(new XElement("RestoreConfigFile", restoreConfigFile));
        }
        // Add channel sources without replacing the user's nuget.config.
        else if (additionalSources is not null)
        {
            var sourceList = string.Join(";", additionalSources);
            if (sourceList.Length > 0)
            {
                propertyGroup.Add(new XElement("RestoreAdditionalProjectSources", sourceList));
            }
        }

try
        {
            var channels = await _packagingService.GetChannelsAsync(cancellationToken, requestedChannel);
            channel = channels.FirstOrDefault(c =>
                c.Type == PackageChannelType.Explicit &&
                c.Mappings is { Length: > 0 } &&
                string.Equals(c.Name, requestedChannel, StringComparisons.ChannelName));
        }
        catch (OperationCanceledException)
        {
            throw;
        }
        catch (Exception ex)
        {
            // A transient packaging-service failure during auto-discovery must not turn
            // `aspire new` into a hard failure. Returning null falls through to the existing
            // ambient + channel-sources path, matching the defensive catches in
            // TryCreateTemporaryNuGetConfigAsync and GetNuGetSourcesAsync.
            _logger.LogWarning(ex, "Failed to resolve local Aspire package source for channel '{Channel}'.", requestedChannel);
            return null;
        }

try
        {
            await foreach (var candidate in channel.Reader.ReadAllAsync(cancellationToken).ConfigureAwait(false))
            {
                yield return candidate;
            }

            await discoveryTask.ConfigureAwait(false);
        }
        finally
        {
            if (!discoveryTask.IsCompleted)
            {
                discoveryCancellationTokenSource.Cancel();
            }

            try
            {
                await discoveryTask.ConfigureAwait(false);
            }
            catch (OperationCanceledException) when (discoveryCancellationTokenSource.IsCancellationRequested)
            {
                // Enumeration can stop before discovery finishes (for example Ctrl+C). In that case
                // cancellation is already being surfaced to the consumer through ReadAllAsync.
            }
        }
